const tz = 'America/Sao_Paulo';
const doctorCode = parseInt($json.doctor_code) || 1;
const patientPhone = $json.patient_phone || null;

let year, month, day;

if ($json.query_date && $json.query_date.trim()) {
  const raw = $json.query_date.trim();
  if (raw.match(/^\d{2}\/\d{2}\/\d{4}$/)) {
    const parts = raw.split('/');
    day = parseInt(parts[0]);
    month = parseInt(parts[1]);
    year = parseInt(parts[2]);
  } else {
    // ISO or other format - extract date in SP timezone
    const d = new Date(raw);
    const spStr = new Intl.DateTimeFormat('en-CA', { timeZone: tz }).format(d);
    const p = spStr.split('-').map(Number);
    year = p[0]; month = p[1]; day = p[2];
  }
} else {
  // Today in SP timezone
  const spStr = new Intl.DateTimeFormat('en-CA', { timeZone: tz }).format(new Date());
  const p = spStr.split('-').map(Number);
  year = p[0]; month = p[1]; day = p[2];
}

// Brazil/SP is permanently UTC-3 (DST abolished in 2019)
// Midnight SP = 03:00 UTC
const startTs = Date.UTC(year, month - 1, day, 3, 0, 0);
const dateStart = new Date(startTs).toISOString();
const dateEnd = new Date(startTs + 24 * 3600 * 1000).toISOString();
const dateLabel = String(day).padStart(2,'0') + '/' + String(month).padStart(2,'0') + '/' + year;

return [{ json: { doctor_code: doctorCode, patient_phone: patientPhone, date_start: dateStart, date_end: dateEnd, date_label: dateLabel } }];

const items = $input.all();
const dateLabel = items[0]?.json?.date_label || 'hoje';
const specialty = items[0]?.json?.specialty || 'clínica';
const clinicalConditions = items[0]?.json?.clinical_conditions || '';
const pacientes = items.map(item => {
  const d = item.json;
  const slotBrt = new Date(d.slot_brt);
  const hora = slotBrt.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit', timeZone: 'America/Sao_Paulo' });
  const examDate = d.exam_date ? new Date(d.exam_date).toLocaleDateString('pt-BR') : null;
  return {
    horario: hora,
    nome: d.patient_name || 'Paciente',
    idade: d.age || null,
    telefone: d.patient_phone,
    exames: d.analise_json || null,
    data_exame: examDate,
    condicoes: d.conditions || null,
    medicacoes: d.medications || null,
    alergias: d.allergies || null
  };
});
return [{ json: {
  date_label: dateLabel,
  specialty: specialty,
  clinical_conditions: clinicalConditions,
  total: pacientes.length,
  pacientes: JSON.stringify(pacientes)
}}];

